@page "/admin/users"
@rendermode InteractiveServer
@using Microsoft.AspNetCore.Identity
@using sv_6d36794f333a418ca1a6fc79e614fa53.Data
@attribute [Authorize(Roles = "Admin")]

@inject UserManager<ApplicationUser> UserManager

<PageTitle>User Management</PageTitle>

<h1>User Management</h1>
<p>Manage all users in the system.</p>

@if (users is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table table-striped">
        <thead>
            <tr>
                <th>Email</th>
                <th>Roles</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var entry in users)
            {
                <tr>
                    <td>@entry.Email</td>
                    <td>@string.Join(", ", entry.Roles)</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<UserWithRoles>? users;

    protected override async Task OnInitializedAsync()
    {
        var allUsers = UserManager.Users.ToList();
        var result = new List<UserWithRoles>();
        foreach (var user in allUsers)
        {
            var roles = await UserManager.GetRolesAsync(user);
            result.Add(new UserWithRoles(user.Email ?? "", roles));
        }
        users = result;
    }

    private record UserWithRoles(string Email, IList<string> Roles);
}

